import { streamText } from 'ai';
import { z } from 'zod';

const detectHallucinations = async (stream) => {
  let confidenceDrift = 0;
  let tokenCount = 0;

  for await (const chunk of stream) {
    const tokens = chunk.toString().split(/\s+/);
    tokenCount += tokens.length;

    // Flag if >30% tokens appear low-confidence (repetitive/short)
    const lowConfTokens = tokens.filter(t => t.length < 3 || /[^a-zA-Z]/.test(t)).length;
    confidenceDrift += lowConfTokens / tokenCount;

    if (confidenceDrift > 0.3) {
      console.warn('🚨 Hallucination detected:', { confidenceDrift, tokenCount });
    }
  }
};

// Usage
const result = await streamText({
  model: openai('gpt-4o'),
  stream: true,
});

detectHallucinations(result.textStream);

import { generateText } from 'ai';
import { z } from 'zod';

const toolCallSchema = z.object({
  name: z.string(),
  args: z.record(z.any()),
  result: z.union([z.string(), z.number(), z.boolean()]),
});

const validateToolCall = (toolCall: any) => {
  const result = toolCallSchema.safeParse(toolCall);
  if (!result.success) {
    console.error('❌ Invalid tool call:', result.error);
    return { valid: false, sanitized: null };
  }
  return { valid: true, sanitized: result.data };
};

const { text } = await generateText({
  model: openai('gpt-4o'),
  tools: {
    calculator: {
      description: 'Calculate math',
      parameters: z.object({ expr: z.string() }),
      execute: async ({ expr }) => {
        const result = validateToolCall({ name: 'calculator', args: { expr }, result: eval(expr) });
        if (!result.valid) throw new Error('Tool validation failed');
        return result.sanitized.result;
      },
    },
  },
});

