import { streamText } from 'ai';

const safeStreamText = async ({ model, prompt }) => {
  const stream = await streamText({ model, prompt });

  return new ReadableStream({
    async start(controller) {
      let buffer = '';
      let confidence = 1.0;

      for await (const chunk of stream.textStream) {
        buffer += chunk;

        // Simple confidence scoring
        const sentences = buffer.split(/[.!?]+/).filter(s => s.trim());
        confidence = sentences.length > 0 ? sentences[sentences.length - 1].length / 100 : 1;

        if (confidence > 0.5 || buffer.length > 200) {
          controller.enqueue(new TextEncoder().encode(buffer));
          buffer = '';
        }
      }

      if (buffer) controller.enqueue(new TextEncoder().encode(buffer));
      controller.close();
    },
  });
};

import { generateText } from 'ai';
import { z } from 'zod';

const safeToolExecutor = (tool) => async (...args) => {
  try {
    const rawResult = await tool(...args);

    // Sanitize output
    const safeResult = z.union([z.string().max(1000), z.number(), z.boolean()])
      .safeParse(rawResult);

    if (!safeResult.success) {
      throw new Error('Tool output validation failed');
    }

    return safeResult.data;
  } catch (error) {
    console.error('Tool error:', error);
    return 'Tool execution failed - please try again';
  }
};

const { text } = await generateText({
  model: openai('gpt-4o'),
  tools: {
    weather: {
      parameters: z.object({ city: z.string() }),
      execute: safeToolExecutor(async ({ city }) => {
        // Real weather API call
        return `Weather in ${city}: 72°F, sunny`;
      }),
    },
  },
});

import { streamText } from 'ai';

const edgeSafeAgent = async (prompt: string) => {
  const MAX_TOKENS = 2000;
  let remainingPrompt = prompt;
  let fullResponse = '';

  while (remainingPrompt) {
    const { text } = await streamText({
      model: openai('gpt-4o'),
      maxTokens: MAX_TOKENS,
      prompt: `Continue from: ${remainingPrompt}\nPrevious: ${fullResponse.slice(-500)}`,
    });

    fullResponse += text;
    remainingPrompt = text.includes('[CONTINUE]') ? remainingPrompt : '';

    // Yield partial results for streaming UI
    if (remainingPrompt) {
      // Stream chunk to client
      console.log('Chunk:', text);
    }
  }

  return fullResponse;
};

